pairs = [('0','0'),('1','1'),('6','9'),('8','8'),('9','6')]
def build(n, final):
    if n==0: return ['']
    if n==1: return ['0','1','8']
    inner = build(n-2, False)
    res = []
    for a,b in pairs:
        if not final and a=='0': continue  # no leading 0
        for s in inner: res.append(a+s+b)
    return res

