visited = set()
def go_back(): robot.turnRight(); robot.turnRight(); robot.move(); robot.turnRight(); robot.turnRight()
def dfs(x, y, d):
    robot.clean(); visited.add((x,y))
    for i in range(4):
        nd = (d+i)%4
        nx, ny = x+dirs[nd][0], y+dirs[nd][1]
        if (nx,ny) not in visited and robot.move():
            dfs(nx, ny, nd); go_back()
        robot.turnRight()

